{
  "id": "cli_arglen_policy",
  "version": 1,
  "summary": "Minimize Windows CLI argument length by preferring file-based payloads.",
  "rules": [
    "Avoid embedding large JSON or prompts directly in command-line arguments.",
    "Write payloads to temp files and pass file paths instead.",
    "Prefer short flags and environment variables for small scalars only."
  ]
}
